# Worked focus: http-py-downgrade-mixed-content — Reject unintended HTTP downgrades, insecure redirects, mixed content, and credential forwarding across weaker channels. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_tls_trust_2(scheme: str, hostname_matches: bool, chain_trusted: bool) -> dict[str, object]:
    assert isinstance(scheme, str)
    if scheme.casefold() != "https":
        return {"accepted": False, "reason": "downgrade"}
    if not hostname_matches:
        return {"accepted": False, "reason": "hostname"}
    if not chain_trusted:
        return {"accepted": False, "reason": "trust chain"}
    return {"accepted": True, "reason": "authenticated transport"}

